package com.cognizant.springlearn.service;
import java.util.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import com.cognizant.springlearn.dao.EmployeeDao; import com.cognizant.springlearn.model.Employee;
@Service public class EmployeeService { private final EmployeeDao dao; public EmployeeService(EmployeeDao dao){this.dao=dao;} @Transactional(readOnly=true) public List<Employee> getAllEmployees(){ return dao.getAllEmployees(); } @Transactional(readOnly=true) public Employee getEmployee(int id){ return dao.getEmployee(id); } }
